@* Displays a single task with priority badge and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">
                    &larr; Move Left
                </button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title"
                       @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                       @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm flex-grow-1" @onclick="Save"
                        disabled="@saving">
                    @(saving ? "Saving..." : "Save")
                </button>
                <button class="btn btn-secondary btn-sm flex-grow-1" @onclick="Cancel"
                        disabled="@saving">
                    Cancel
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        try
        {
            await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            ResetForm();
            IsVisible = false;
            await OnTaskCreated.InvokeAsync();
        }
        finally
        {
            saving = false;
        }
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@* Search input for filtering tasks by title *@

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title..."
           @bind="SearchText" @bind:event="oninput" @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task NotifyChanged() => await SearchTextChanged.InvokeAsync(SearchText);
}

@* A single Kanban column displaying filtered tasks and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => MoveTask(task.Id, LeftStatus!)"
                          OnMoveRight="() => MoveTask(task.Id, RightStatus!)" />
            }
            <AddTaskForm DefaultStatus="@ColumnName" OnTaskCreated="OnTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback OnTaskCreated { get; set; }

    private bool CanMoveLeft => LeftStatus is not null;
    private bool CanMoveRight => RightStatus is not null;

    private async Task MoveTask(int taskId, string newStatus)
    {
        await OnMoveTask.InvokeAsync((taskId, newStatus));
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

