@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFilteredTasks("Done")"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="LoadTasks" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            await LoadTasks();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
"}

